1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const uniqueCells = (cells: Cell[]): Cell[] =>
15	  Array.from(new Map(cells.map((c) => [cellKey(c), c])).values());
16	
17	const cellAndNeighbors = (cell: Cell): Cell[] => [cell, ...neighborsOf(cell)];
18	
19	export function nextGeneration(cells: Cell[]): Cell[] {
20	  const liveKeys = new Set(cells.map(cellKey));
21	  const isLive = (cell: Cell): boolean => liveKeys.has(cellKey(cell));
22	
23	  const countLiveNeighbors = (cell: Cell): number =>
24	    neighborsOf(cell).filter(isLive).length;
25	
26	  const willBeAlive = (cell: Cell): boolean => {
27	    const neighbors = countLiveNeighbors(cell);
28	    return neighbors === 3 || (neighbors === 2 && isLive(cell));
29	  };
30	
31	  const candidates = uniqueCells(cells.flatMap(cellAndNeighbors));
32	  return candidates.filter(willBeAlive);
33	}
